// ══════════════════════════════════════════════════
//  ÂNGULOS — Transferidor 360° com ponteiro arrastável + modelo 3D
//  0° = baixo, 90° = direita, 180° = cima, 270° = esquerda
// ══════════════════════════════════════════════════

let currentAngulo = 0;
let _angDragging  = false;

const TERMINAL_IMG = new Image();
TERMINAL_IMG.src   = 'data:image/png;base64,';

function renderAngulos() {
  _angDrawAll();
  updateRangeTrack(0);
}

window.addEventListener('resize', () => {
  if (document.getElementById('screen-angulos') &&
      document.getElementById('screen-angulos').classList.contains('active')) {
    _angDrawAll(); _resize3D();
  }
});

// ── Range slider ──
function updateRangeTrack(val) {
  const el = document.getElementById('ang-range');
  if (!el) return;
  const pct = (val / 355) * 100;
  el.style.background = `linear-gradient(to right,#4a90ff 0%,#4a90ff ${pct}%,rgba(74,144,255,.18) ${pct}%,rgba(74,144,255,.18) 100%)`;
}

function selAngRange(val) {
  currentAngulo = parseInt(val);
  document.getElementById('ang-deg-big').textContent = currentAngulo + '°';
  updateRangeTrack(currentAngulo);
  _angDrawAll();
}

// ── Resize ──
function resizeAngCanvas() {
  const canvas = document.getElementById('ang-canvas');
  const container = document.getElementById('ang-left-panel');
  if (!canvas || !container) return;
  const size = Math.min(container.clientWidth, container.clientHeight) * 0.92;
  canvas.width  = size;
  canvas.height = size;
}

// ── Draw tudo ──
function _angDrawAll() {
  resizeAngCanvas();
  _drawTransferidor();
  _draw3DHose();
}

// ═══════════════════════════════════════════════════
//  TRANSFERIDOR CANVAS
// ═══════════════════════════════════════════════════
function _drawTransferidor() {
  const canvas = document.getElementById('ang-canvas');
  if (!canvas) return;
  const ctx = canvas.getContext('2d');
  const W = canvas.width, H = canvas.height;
  ctx.clearRect(0, 0, W, H);

  const cx = W / 2, cy = H / 2;
  const R  = Math.min(W, H) * 0.46;

  // Fundo branco
  ctx.beginPath(); ctx.arc(cx, cy, R * 1.08, 0, Math.PI * 2);
  ctx.fillStyle = '#fff'; ctx.fill();
  ctx.strokeStyle = '#ccc'; ctx.lineWidth = 1.5; ctx.stroke();

  // Graduação: 0° = baixo (Math.PI/2), sentido horário
  // Ângulo 0° → bottom (π/2), 90° → right (0), 180° → top (-π/2), 270° → left (π)
  // 0°=baixo, 90°=direita, 180°=cima, 270°=esquerda
  function angToRad(deg) {
    return Math.PI / 2 - deg * Math.PI / 180;
  }

  // Ticks + labels — 0°=baixo, crescendo horário pela direita
  for (let deg = 0; deg < 360; deg++) {
    const a = angToRad(deg);
    const maj10 = deg % 10 === 0;
    const maj5  = deg % 5 === 0 && !maj10;
    const tickLen = maj10 ? R * 0.10 : maj5 ? R * 0.06 : R * 0.035;
    const lw = maj10 ? 1.4 : maj5 ? 0.9 : 0.5;

    // Ponto na borda: cx + cos(a)*R, cy + sin(a)*R
    // angToRad: a = π/2 - deg*π/180
    // deg=0 → a=π/2 → cos=0, sin=1 → (cx, cy+R) = BAIXO ✓
    // deg=90 → a=0 → cos=1, sin=0 → (cx+R, cy) = DIREITA ✓
    const px1 = cx + Math.cos(a) * R;
    const py1 = cy + Math.sin(a) * R;   // +sin porque y cresce para baixo no canvas
    const px2 = cx + Math.cos(a) * (R - tickLen);
    const py2 = cy + Math.sin(a) * (R - tickLen);

    ctx.beginPath();
    ctx.moveTo(px1, py1);
    ctx.lineTo(px2, py2);
    ctx.strokeStyle = '#111'; ctx.lineWidth = lw; ctx.stroke();

    if (maj10) {
      const lr = R - tickLen - (deg % 30 === 0 ? 15 : 10);
      const lx = cx + Math.cos(a) * lr;
      const ly = cy + Math.sin(a) * lr;
      ctx.save();
      ctx.translate(lx, ly);
      // Rotaciona o texto para ficar tangencial ao círculo, legível
      // O ângulo 'a' aponta para fora — girar texto perpendicular a isso
      ctx.rotate(a - Math.PI / 2);
      ctx.font = `${deg % 30 === 0 ? '700 12px' : '500 9px'} Inter,sans-serif`;
      ctx.fillStyle = '#111';
      ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
      ctx.fillText(deg, 0, 0);
      ctx.restore();
    }
  }

  // Arco do ângulo atual (0° → currentAngulo)
  if (currentAngulo !== 0) {
    const aStart = angToRad(0);
    const aEnd   = angToRad(currentAngulo);
    ctx.beginPath();
    ctx.moveTo(cx, cy);
    ctx.arc(cx, cy, R * 0.36, aStart, aEnd, false);
    ctx.closePath();
    ctx.fillStyle = 'rgba(26,86,219,0.07)'; ctx.fill();
    ctx.beginPath();
    ctx.arc(cx, cy, R * 0.36, aStart, aEnd, false);
    ctx.strokeStyle = 'rgba(26,86,219,0.25)'; ctx.lineWidth = 1.5; ctx.stroke();
  }

  // Hub central
  ctx.beginPath(); ctx.arc(cx, cy, R * 0.06, 0, Math.PI * 2);
  ctx.fillStyle = '#eee'; ctx.fill();
  ctx.strokeStyle = '#bbb'; ctx.lineWidth = 1.5; ctx.stroke();

  // ── Ponteiro FIXO (0° = baixo) — frente ──
  _drawPointerFixed(ctx, cx, cy, R);

  // ── Ponteiro MÓVEL (currentAngulo) — atrás do fixo ──
  _drawPointerMobile(ctx, cx, cy, R, currentAngulo);

  // Hub central sobreposto
  ctx.beginPath(); ctx.arc(cx, cy, R * 0.045, 0, Math.PI * 2);
  ctx.fillStyle = '#fff'; ctx.fill();
  ctx.strokeStyle = '#aaa'; ctx.lineWidth = 1; ctx.stroke();

  // ── Drag area ──
  _setupAngDrag(canvas, cx, cy);
}

function _drawPointerFixed(ctx, cx, cy, R) {
  // 0° = baixo → ângulo canvas = -π/2 (apontando para baixo)
  // O terminal aponta para baixo com o corpo saindo para cima
  const angle = Math.PI / 2; // baixo

  if (TERMINAL_IMG.complete && TERMINAL_IMG.naturalWidth > 0) {
    const h = R * 0.48;
    const w = h * (TERMINAL_IMG.naturalWidth / TERMINAL_IMG.naturalHeight);
    ctx.save();
    ctx.translate(cx, cy);
    // Imagem aponta para cima (cabeça para cima) — girar 180° para apontar para baixo (0°)
    // mas manter no centro vertical
    // Adiciona contorno preto (sombra)
    ctx.shadowColor = '#000';
    ctx.shadowBlur = 6;
    ctx.drawImage(TERMINAL_IMG, -w / 2, -h * 0.2, w, h);
    ctx.shadowBlur = 0;
    ctx.restore();
  } else {
    _drawSimplePointer(ctx, cx, cy, Math.PI / 2, R * 0.44, '#222');
  }
}

function _drawPointerMobile(ctx, cx, cy, R, deg) {
  // angToRad: deg=0 → bottom, deg=90 → right
  const radCanvas = -(deg * Math.PI / 180); // rotação no canvas (sentido horário visualmente)

  ctx.save();
  ctx.translate(cx, cy);
  ctx.rotate(radCanvas);

  if (TERMINAL_IMG.complete && TERMINAL_IMG.naturalWidth > 0) {
    // Mesmo layout do fixo mas colorido em azul via compositing
    const h = R * 0.48;
    const w = h * (TERMINAL_IMG.naturalWidth / TERMINAL_IMG.naturalHeight);
    // Tinge de azul
    ctx.globalAlpha = 0.85;
    // Desenha colorido: offscreen canvas com tint
    const off = document.createElement('canvas');
    off.width = w; off.height = h;
    const octx = off.getContext('2d');
    octx.drawImage(TERMINAL_IMG, 0, 0, w, h);
    octx.globalCompositeOperation = 'source-atop';
    octx.fillStyle = '#1a56db';
    octx.globalAlpha = 0.55;
    octx.fillRect(0, 0, w, h);
    ctx.shadowColor = '#000';
    ctx.shadowBlur = 6;
    ctx.drawImage(off, -w / 2, -h * 0.2, w, h);
    ctx.shadowBlur = 0;
    ctx.globalAlpha = 1;
  } else {
    // Fallback linha azul
    const len = R * 0.42;
    ctx.beginPath(); ctx.moveTo(0, 0); ctx.lineTo(0, len);
    ctx.strokeStyle = '#1a56db'; ctx.lineWidth = 3; ctx.lineCap = 'round'; ctx.stroke();
    ctx.beginPath(); ctx.arc(0, len, R * 0.04, 0, Math.PI * 2);
    ctx.fillStyle = '#1a56db'; ctx.fill();
  }

  ctx.restore();
}

function _drawSimplePointer(ctx, cx, cy, angle, len, color) {
  ctx.save();
  ctx.translate(cx, cy);
  ctx.rotate(angle - Math.PI / 2);
  ctx.beginPath(); ctx.moveTo(0, 0); ctx.lineTo(0, len);
  ctx.strokeStyle = color; ctx.lineWidth = 3; ctx.lineCap = 'round'; ctx.stroke();
  ctx.restore();
}

// ── Drag para girar o ponteiro móvel ──
function _setupAngDrag(canvas, cx, cy) {
  // Remove listeners antigos
  canvas.onmousedown  = null; canvas.ontouchstart = null;

  function getAngle(e) {
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width  / rect.width;
    const scaleY = canvas.height / rect.height;
    const clientX = e.touches ? e.touches[0].clientX : e.clientX;
    const clientY = e.touches ? e.touches[0].clientY : e.clientY;
    const x = (clientX - rect.left) * scaleX - cx;
    const y = (clientY - rect.top)  * scaleY - cy;
    // angToRad = π/2 - deg*π/180, então deg = (π/2 - θ)*180/π
    // θ = atan2(dy, dx) onde dy = y no canvas (positivo para baixo = 0°)
    const theta = Math.atan2(y, x);
    let deg = Math.round(((Math.PI / 2 - theta) * 180 / Math.PI + 360) % 360);
    deg = Math.round(deg / 5) * 5; // snap a cada 5°
    return deg;
  }

  function startDrag(e) {
    _angDragging = true;
    updateFromEvent(e);
  }
  function duringDrag(e) {
    if (!_angDragging) return;
    e.preventDefault();
    updateFromEvent(e);
  }
  function endDrag() { _angDragging = false; }

  function updateFromEvent(e) {
    const deg = getAngle(e);
    currentAngulo = deg;
    document.getElementById('ang-deg-big').textContent = deg + '°';
    const rangeEl = document.getElementById('ang-range');
    if (rangeEl) { rangeEl.value = deg; updateRangeTrack(deg); }
    _angDrawAll();
  }

  canvas.onmousedown  = startDrag;
  canvas.ontouchstart = e => { e.preventDefault(); startDrag(e); };
  window.onmousemove  = duringDrag;
  window.ontouchmove  = e => { if (_angDragging) { e.preventDefault(); duringDrag(e); } };
  window.onmouseup    = endDrag;
  window.ontouchend   = endDrag;
  canvas.style.cursor = 'grab';
}

const _GP0deg='';
const _GN0deg='';
const _GI0deg='';
const _GP90deg='';
const _GN90deg='';
const _GI90deg='';
const _GP180deg='';
const _GN180deg='';
const _GI180deg='';
const _GP270deg='';
const _GN270deg='';
const _GI270deg='';

// ═══════════════════════════════════════════════════
//  MODELO 3D — 4 geometrias reais (0°/90°/180°/270°)
//  Fonte: COMPOSIÇÃO_MANGUEIRAS.gltf
//  Mangueira em Y, escalada para 5 units
// ═══════════════════════════════════════════════════
let _threeScene = null;

function _b64F32(b){const d=atob(b),u=new Uint8Array(d.length);for(let i=0;i<d.length;i++)u[i]=d.charCodeAt(i);return new Float32Array(u.buffer);}
function _b64U32(b){const d=atob(b),u=new Uint8Array(d.length);for(let i=0;i<d.length;i++)u[i]=d.charCodeAt(i);return new Uint32Array(u.buffer);}

function _makeGeo(T, p, n, i) {
  const g = new T.BufferGeometry();
  // Rotaciona eixos: Y(longo)→X, X→Y, Z→Z para Three.js horizontal
  const pa = _b64F32(p);
  const na = _b64F32(n);
  const rot = new Float32Array(pa.length);
  const ron = new Float32Array(na.length);
  for (let k=0; k<pa.length; k+=3) {
    rot[k]   =  pa[k+1]; // Y→X
    rot[k+1] = -pa[k];   // -X→Y
    rot[k+2] =  pa[k+2]; // Z→Z
    ron[k]   =  na[k+1];
    ron[k+1] = -na[k];
    ron[k+2] =  na[k+2];
  }
  g.setAttribute('position', new T.BufferAttribute(rot, 3));
  g.setAttribute('normal',   new T.BufferAttribute(ron, 3));
  g.setIndex(new T.BufferAttribute(_b64U32(i), 1));
  return g;
}

// Pré-compila geometrias (lazy - só quando Three.js carregado)
let _geos = null;
function _ensureGeos(T) {
  if (_geos) return;
  _geos = {
    0:   _makeGeo(T, _GP0deg,   _GN0deg,   _GI0deg),
    90:  _makeGeo(T, _GP90deg,  _GN90deg,  _GI90deg),
    180: _makeGeo(T, _GP180deg, _GN180deg, _GI180deg),
    270: _makeGeo(T, _GP270deg, _GN270deg, _GI270deg),
  };
}

function _draw3DHose() {
  const c = document.getElementById('ang-hose-3d');
  if (!c) return;
  if (window.innerWidth < 600) return;
  if (!window.THREE) {
    const s = document.createElement('script');
    s.src = 'https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js';
    s.onload = () => _init3DHose(c);
    document.head.appendChild(s); return;
  }
  _init3DHose(c);
}

function _resize3D() {
  if (!_threeScene) return;
  const ct = document.getElementById('ang-hose-3d');
  if (!ct||!ct.clientWidth) return;
  _threeScene.renderer.setSize(ct.clientWidth, ct.clientHeight);
  _threeScene.cam.aspect = ct.clientWidth / ct.clientHeight;
  _threeScene.cam.updateProjectionMatrix();
}

function _init3DHose(ct) {
  const T = window.THREE;
  if (_threeScene) { _updateHoseAngle(currentAngulo); return; }

  const W = ct.clientWidth||520, H = ct.clientHeight||380;
  const renderer = new T.WebGLRenderer({antialias:true});
  renderer.setSize(W,H);
  renderer.setPixelRatio(Math.min(devicePixelRatio,2));
  renderer.setClearColor(0xe8eaf0,1);
  renderer.shadowMap.enabled = true;
  ct.innerHTML=''; ct.appendChild(renderer.domElement);

  const scene = new T.Scene();
  const cam = new T.PerspectiveCamera(30,W/H,0.1,100);
  cam.position.set(4.5,2.5,9.0);
  cam.lookAt(0,-0.2,0);

  scene.add(new T.AmbientLight(0xe8eeff,0.75));
  const sun = new T.DirectionalLight(0xffffff,0.85);
  sun.position.set(5,10,7); sun.castShadow=true; scene.add(sun);
  const fill = new T.DirectionalLight(0xaabbdd,0.40);
  fill.position.set(-6,3,-5); scene.add(fill);
  const bot = new T.DirectionalLight(0x8899bb,0.20);
  bot.position.set(0,-8,3); scene.add(bot);

  // Material metálico — cor cinza aço como o GLTF original
  const mat = new T.MeshPhongMaterial({
    color:0xb2bac2, shininess:75, specular:0x606870, side:T.DoubleSide
  });
  // Mangueira mais escura
  const matH = new T.MeshPhongMaterial({
    color:0x222228, shininess:12, specular:0x080810, side:T.DoubleSide
  });

  _ensureGeos(T);

  // Mesh que troca de geometria conforme o ângulo
  const mesh = new T.Mesh(_geos[0], mat);
  mesh.castShadow = mesh.receiveShadow = true;
  scene.add(mesh);

  _threeScene = {renderer, scene, cam, mesh, mat, matH};

  (function loop(){requestAnimationFrame(loop);renderer.render(scene,cam);})();
  _updateHoseAngle(currentAngulo);
}

function _updateHoseAngle(deg) {
  if (!_threeScene || !_geos) return;
  // Snap para o ângulo mais próximo disponível: 0, 90, 180, 270
  const snap = [0,90,180,270].reduce((a,b) => {
    const da = Math.abs(((deg-a)%360+360)%360);
    const db = Math.abs(((deg-b)%360+360)%360);
    return (da<=db&&da<=360-da)||(da<=db) ? a : b;
  });
  const normSnap = ((snap%360)+360)%360;
  if (_geos[normSnap]) {
    _threeScene.mesh.geometry = _geos[normSnap];
  }
}